mapper.select:
SELECT c.course_code AS course_id, c.course_name, p.name AS professor, TO_CHAR(sm.year) || '-' || CASE sm.term WHEN 'SPRING' THEN '1' WHEN 'FALL' THEN '2' ELSE sm.term END || '학기' AS semester, c.credits AS credit, CASE WHEN r.review_id IS NULL THEN 'PENDING' ELSE 'SUBMITTED' END AS status, r.rating_overall, TO_CHAR(r.created_at, 'YYYY-MM-DD HH24:MI:SS') AS created_at FROM student s JOIN enrollment e ON e.student_id = s.student_id AND e.status = 'ENROLLED' JOIN course_section cs ON cs.section_id = e.section_id JOIN semester sm ON sm.semester_id = cs.semester_id JOIN course c ON c.course_id = cs.course_id JOIN professor p ON p.professor_id = cs.professor_id LEFT JOIN review r ON r.enrollment_id = e.enrollment_id WHERE s.user_id = #{userId}
AND sm.is_current = 1
AND TO_CHAR(sm.year) || '-' || CASE sm.term WHEN 'SPRING' THEN '1' WHEN 'FALL' THEN '2' ELSE sm.term END || '학기' = #{semester}
ORDER BY c.course_name, cs.section_no
